@Composable
fun UserAvatar(userId: String) {
    val bitmap = remember(userId) { loadAvatarPlaceholder(userId) }
    Image(bitmap.asImageBitmap(), contentDescription = null)
}

@Composable
fun FilterPanel() {
    var expanded by remember { mutableStateOf(false) }
    var query by rememberSaveable { mutableStateOf("") }

    Column {
        TextField(value = query, onValueChange = { query = it })
        Button(onClick = { expanded = !expanded }) { Text("Bộ lọc") }
    }
}

@Parcelize
data class SearchFilter(val cityId: String?, val remoteOnly: Boolean) : Parcelable

@Composable
fun FilterOwner() {
    var filter by rememberSaveable { mutableStateOf(SearchFilter(null, false)) }
}
